sql.where:
spl.status IN (1, 3)

    AND (o.order_no COLLATE utf8mb4_unicode_ci LIKE CONCAT('%',#{data.orderNo},'%')
    OR po.order_no COLLATE utf8mb4_unicode_ci LIKE CONCAT('%',#{data.orderNo},'%')
    OR sro.order_no COLLATE utf8mb4_unicode_ci LIKE CONCAT('%',#{data.orderNo},'%')
    OR spl.out_trade_no COLLATE utf8mb4_unicode_ci LIKE CONCAT('%',#{data.orderNo},'%'))


    AND spl.wx_transaction_no LIKE CONCAT('%',#{data.merchantOrderNo},'%')


    AND spl.status = #{data.type}


    AND spl.created_at >= #{data.startTime}


    AND spl.created_at <= #{data.endTime}
